#include <stdio.h>
#include <stdlib.h>

// Structure for a pair
typedef struct {
    int first;
    int second;
} Pair;

// Function to perform DFS
void dfs(int** grid, int row, int col, int baseRow, int baseCol, int** vis, Pair** shape, int* shapeSize) {
    // Mark as visited
    vis[row][col] = 1;
    // Store relative position
    shape[*shapeSize] = (Pair){row - baseRow, col - baseCol};
    (*shapeSize)++;

    // All 4 directions
    int drow[] = {-1, 0, 1, 0};
    int dcol[] = {0, 1, 0, -1};

    // Explore all directions
    for (int i = 0; i < 4; i++) {
        int nrow = row + drow[i];
        int ncol = col + dcol[i];

        // Check bounds and if land and not visited
        if (nrow >= 0 && nrow < 500 &&
            ncol >= 0 && ncol < 500 &&
            !vis[nrow][ncol] && grid[nrow][ncol] == 1) {
            dfs(grid, nrow, ncol, baseRow, baseCol, vis, shape, shapeSize);
        }
    }
}

// Function to count distinct islands
int countDistinctIslands(int** grid, int gridSize) {
    int n = gridSize;
    int m = gridSize;
    int** vis = (int**)malloc(n * sizeof(int*));
    for (int i = 0; i < n; i++) {
        vis[i] = (int*)malloc(m * sizeof(int));
    }
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < m; j++) {
            vis[i][j] = 0;
        }
    }
    int count = 0;
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < m; j++) {
            if (grid[i][j] == 1 && !vis[i][j]) {
                Pair* shape = (Pair*)malloc(500 * sizeof(Pair));
                int shapeSize = 0;
                dfs(grid, i, j, i, j, vis, &shape, &shapeSize);
                // Add shape to set
                count++;
                free(shape);
            }
        }
    }
    return count;
}

int main() {
    int gridSize = 5;
    int** grid = (int**)malloc(gridSize * sizeof(int*));
    for (int i = 0; i < gridSize; i++) {
        grid[i] = (int*)malloc(gridSize * sizeof(int));
    }
    // Initialize grid
    for (int i = 0; i < gridSize; i++) {
        for (int j = 0; j < gridSize; j++) {
            grid[i][j] = 0;
        }
    }
    grid[0][0] = 1;
    grid[0][1] = 1;
    grid[1][0] = 1;
    grid[1][1] = 1;
    printf("%d\n", countDistinctIslands(grid, gridSize));
    return 0;
}

